def median(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)

    if n % 2 == 1:
        return float(nums[n // 2])
    else:
        mid_right = nums[n // 2]
        mid_left = nums[n // 2 - 1]
        return (mid_right + mid_left) / 2.0
